const rows = $input.all().map((item) => item.json ?? {});
if (!rows.length) {
  throw new Error('The cloud labels query returned no rows.');
}

const batchIds = [...new Set(rows.map((row) => String(row.batch_id ?? '').trim()).filter(Boolean))];
if (!batchIds.length) {
  throw new Error('The cloud labels query did not return a batch id.');
}
const batchId = batchIds.length === 1 ? batchIds[0] : `multiple-${batchIds.join('-')}`;
const bannerDataUri = 'data:image/png;base64,';

const escapeHtml = (value) => String(value ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');

const text = (value) => String(value ?? '').trim();
const canonicalLine = (value) => text(value).replace(/\s+/g, ' ').toLowerCase();
const dedupeLines = (values) => {
  const seen = new Set();
  const result = [];
  for (const value of values) {
    const clean = text(value);
    if (!clean) continue;
    const key = canonicalLine(clean);
    if (seen.has(key)) continue;
    seen.add(key);
    result.push(clean);
  }
  return result;
};

const labels = rows.map((row) => ({
  payer: text(row.payer),
  address1: text(row['Address 1']),
  address2: text(row['Address 2']),
  town: text(row.town),
  postcode: text(row.postcode).toUpperCase(),
  parentTags: Number(row.parent_tags ?? 0),
  regularTags: Number(row.regular_tags ?? 0),
  keyTags: Number(row.key_tags ?? 0),
  totalItems: Number(row.total_items ?? 0),
}));

const blankLabel = '<div class="label blank"></div>';
const pageSize = 21;
const sheets = [];
for (let i = 0; i < labels.length; i += pageSize) {
  const chunk = labels.slice(i, i + pageSize);
  while (chunk.length < pageSize) chunk.push(null);
  sheets.push(chunk);
}

const renderLabel = (label) => {
  if (!label) return blankLabel;
  const lines = dedupeLines([label.address1, label.address2, label.town]);
  const counts = [];
  if (label.parentTags) counts.push(`${label.parentTags} parent`);
  if (label.regularTags) counts.push(`${label.regularTags} regular`);
  if (label.keyTags) counts.push(`${label.keyTags} key`);
  const countsText = counts.length ? escapeHtml(counts.join(' / ')) : '';
  return `
    <div class="label">
      <div class="content">
        <div class="line payer">${escapeHtml(label.payer)}</div>
        ${lines.map((line) => `<div class="line">${escapeHtml(line)}</div>`).join('')}
        <div class="line postcode">${escapeHtml(label.postcode)}</div>
      </div>
      ${countsText ? `<div class="meta">${countsText}</div>` : '<div class="meta"></div>'}
      <img class="banner" src="${bannerDataUri}" alt="Avondale Tennis Club">
    </div>`;
};

const html = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <title>J8160 Labels</title>
  <style>
    @page {
      size: A4;
      margin: 0;
    }
    * {
      box-sizing: border-box;
    }
    html, body {
      margin: 0;
      padding: 0;
      width: 210mm;
      background: #fff;
    }
    body {
      font-family: Arial, Helvetica, sans-serif;
      color: #000;
      -webkit-print-color-adjust: exact;
      print-color-adjust: exact;
    }
    .sheet {
      width: 210mm;
      height: 297mm;
      padding: 15.1mm 0 0 7.1mm;
      display: grid;
      grid-template-columns: repeat(3, 63.5mm);
      grid-auto-rows: 38.1mm;
      column-gap: 2.65mm;
      row-gap: 0;
      page-break-after: always;
    }
    .sheet:last-child {
      page-break-after: auto;
    }
    .label {
      position: relative;
      width: 63.5mm;
      height: 38.1mm;
      padding: 3.2mm 3.2mm 2.2mm 3.6mm;
      overflow: hidden;
    }
    .content {
      position: relative;
      z-index: 1;
      height: 100%;
      padding-bottom: 7.5mm;
      overflow: hidden;
    }
    .blank {
      visibility: hidden;
    }
    .line {
      line-height: 1.15;
      font-size: 10.2pt;
      white-space: nowrap;
      overflow: hidden;
      text-overflow: ellipsis;
    }
    .payer {
      font-weight: 700;
      margin-bottom: 0.7mm;
    }
    .postcode {
      margin-top: 0.7mm;
      font-weight: 700;
      letter-spacing: 0.3px;
    }
    .meta {
      position: absolute;
      left: 3.6mm;
      right: 23mm;
      bottom: 2.2mm;
      z-index: 2;
      font-size: 7.2pt;
      line-height: 1.1;
      color: #444;
      white-space: nowrap;
      overflow: hidden;
      text-overflow: ellipsis;
    }
    .banner {
      position: absolute;
      right: 1.5mm;
      bottom: 1.5mm;
      z-index: 3;
      display: block;
      width: 21mm;
      height: auto;
      max-height: 6mm;
      object-fit: contain;
      object-position: right bottom;
      pointer-events: none;
    }
  </style>
</head>
<body>
  ${sheets.map((sheet) => `<section class="sheet">${sheet.map(renderLabel).join('')}</section>`).join('')}
</body>
</html>`;

return [{
  json: {
    batch_id: batchId,
    label_count: labels.length,
    page_count: sheets.length,
    labels,
  },
  binary: {
    data: {
      data: Buffer.from(html, 'utf8').toString('base64'),
      mimeType: 'text/html',
      fileName: 'index.html',
      fileExtension: 'html',
    },
  },
}];

const item = $input.first();
const binary = item.binary?.data;
if (!binary?.data) {
  throw new Error('Gotenberg did not return a PDF binary payload.');
}
const batchId = String(item.json?.batch_id ?? 'unknown').replace(/[^A-Za-z0-9_-]+/g, '-');
return [{
  json: {
    ...(item.json ?? {}),
    generated_at: new Date().toISOString(),
  },
  binary: {
    data: {
      ...binary,
      mimeType: 'application/pdf',
      fileName: `j8160-labels-batch-${batchId}.pdf`,
      fileExtension: 'pdf',
    },
  },
}];
